import type { Player } from '../types';
import { ResultBuilder, type GameActionResult, type CardStateChange } from './ResultBuilder';

export type CardRarity = 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
export type CardType = 'attack' | 'skill' | 'power' | 'curse' | 'status';
export type CardTarget = 'self' | 'single_enemy' | 'all_enemies' | 'random_enemy';

export interface Card {
    id: string;
    name: string;
    description: string;
    type: CardType;
    rarity: CardRarity;
    cost: number;
    target: CardTarget;
    effects: CardEffect[];
    icon: string;
    flavor?: string;
    upgrade?: CardUpgrade;
    tags?: string[];
}

export interface CardEffect {
    type: CardEffectType;
    value?: number;
    times?: number;
    condition?: CardCondition;
    followUp?: CardEffect;
}

export type CardEffectType = 
    | 'damage' | 'block' | 'heal' | 'gain_energy' | 'draw' | 'discard'
    | 'apply_vulnerable' | 'apply_weak' | 'apply_strength' | 'apply_dexterity'
    | 'remove_debuff' | 'remove_all_debuff' | 'gain_strength' | 'gain_dexterity'
    | 'exhaust' | 'return_to_hand' | 'duplicate' | 'upgrade_random'
    | 'random_debuff' | 'life_steal' | 'thorns' | 'regen'
    | 'double_damage' | 'double_block' | 'retain' | 'intangible';

export interface CardCondition {
    type: 'hp_below' | 'hp_above' | 'hand_size' | 'deck_size' | 'has_buff' | 'has_debuff' | 'combo';
    value: number;
}

export interface CardUpgrade {
    name?: string;
    description?: string;
    cost?: number;
    effects?: CardEffect[];
}

export interface CardCombo {
    id: string;
    name: string;
    description: string;
    requiredCards: string[];
    bonusEffect: CardEffect[];
    icon: string;
}

export interface CardPack {
    id: string;
    name: string;
    description: string;
    cost: number;
    cards: { rarity: CardRarity; count: number }[];
    guaranteed?: CardRarity;
    icon: string;
}

export interface DeckState {
    deck: Card[];
    hand: Card[];
    discard: Card[];
    exhaust: Card[];
    energy: number;
    maxEnergy: number;
    drawCount: number;
}

